8	// renderInstructionsForGuardrails returns the post-{{.AttemptDir}}-substitution
9	// instructions string for the given harness selector. Guardrail tests assert
10	// on this pre-XML-escape form so substring checks against `<bead-id>`,
11	// `<specific-paths>`, etc. are not distorted by XML entity encoding (the
12	// rendered prompt encloses instructions in <instructions>...</instructions>
13	// and so escapes angle brackets and apostrophes). The bead body itself is
14	// excluded — invariants must come from the static prompt, not the bead.
15	func renderInstructionsForGuardrails(t *testing.T, harness, contextBudget string) string {
16		t.Helper()
17		const attemptDir = ".ddx/executions/20260101T000000-guardrails"
18		raw := executeBeadInstructionsText(harness)
19		return strings.ReplaceAll(raw, "{{.AttemptDir}}", attemptDir)
20	}
