210	// TestExecuteBeadInstructionsMissingGoverningGate covers AC5: non-minimal
211	// renders include executeBeadMissingGoverningText when refs are empty;
212	// contextBudget=="minimal" omits governing refs entirely (replaced by the
213	// cheap-tier "No governing references." note).
214	func TestExecuteBeadInstructionsMissingGoverningGate(t *testing.T) {
215		full := renderFullPromptForGuardrails(t, "claude", "")
216		if !strings.Contains(full, executeBeadMissingGoverningText) {
217			t.Fatalf("full-budget render with empty refs must include executeBeadMissingGoverningText")
218		}
219		minimal := renderFullPromptForGuardrails(t, "claude", "minimal")
220		if strings.Contains(minimal, executeBeadMissingGoverningText) {
221			t.Errorf("minimal-budget render must NOT include executeBeadMissingGoverningText")
222		}
223		if !strings.Contains(minimal, "No governing references") {
224			t.Errorf("minimal-budget render must contain its short fallback note")
225		}
226		fullA := renderFullPromptForGuardrails(t, "agent", "")
227		if !strings.Contains(fullA, executeBeadMissingGoverningText) {
228			t.Fatalf("agent variant full-budget render with empty refs must include executeBeadMissingGoverningText")
229		}
230	}
