232	// TestExecuteBeadInstructionsSizeFloor is AC1 for ddx-fcdbc731: both
233	// prompt variants must be at least 30% shorter (word count) than the
234	// pre-tightening baseline. Hard-coded baselines from TestPromptSizeReport
235	// at HEAD before the shared-block extraction dep landed.
236	func TestExecuteBeadInstructionsSizeFloor(t *testing.T) {
237		// Pre-tightening baselines from TestPromptSizeReport before ddx-fcdbc731.
238		const (
239			baselineClaude = 1048
240			baselineAgent  = 968
241			floor          = 0.70 // ≥30% reduction; words ≤ 0.70 * baseline
242		)
243		cases := []struct {
244			variant, harness string
245			baseline         int
246		}{
247			{"claude", "claude", baselineClaude},
248			{"agent", "agent", baselineAgent},
249		}
250		for _, c := range cases {
251			c := c
252			t.Run(c.variant, func(t *testing.T) {
253				rendered := renderFullPromptForGuardrails(t, c.harness, "")
254				words := len(strings.Fields(rendered))
255				limit := int(float64(c.baseline) * floor)
256				if words > limit {
257					t.Errorf("AC2 size floor: %s variant rendered %d words; must be ≤ %d (%.0f%% of baseline %d)",
258						c.variant, words, limit, floor*100, c.baseline)
259				}
260				t.Logf("%s variant rendered %d words (baseline %d, limit %d)",
261					c.variant, words, c.baseline, limit)
262			})
263		}
264	}
