382	func contains(haystack []string, needle string) bool {
383		for _, h := range haystack {
384			if h == needle {
385				return true
386			}
387		}
388		return false
389	}
390	
391	func anyContains(s string, needles []string) bool {
392		for _, n := range needles {
393			if strings.Contains(s, n) {
394				return true
395			}
396		}
397		return false
398	}
