1	// Package accheck mechanically verifies acceptance criteria against the
2	// working tree and diff. It is invoked by `ddx bead ac-check <id>` to produce
3	// a structured per-AC result file that both implementer (self-check
4	// pre-commit) and reviewer (gate ratification) consume.
5	//
6	// Per ddx-c739d7ec: the tool classifies each AC line into a kind
7	// (test-name | build-gate | negative | symbol | mechanical | prose) then
8	// resolves evidence mechanically. Prose AC always yields needs_judgment;
9	// never auto-pass, never auto-fail.
10	package accheck
11	
12	import (
13		"bufio"
14		"fmt"
15		"io"
16		"os/exec"
17		"path/filepath"
18		"regexp"
19		"strings"
20	)
21	
22	// SchemaVersion is bumped when the output JSON shape changes incompatibly.
23	const SchemaVersion = 1
24	
25	// Kind classifies an AC line by the evidence we know how to gather for it.
26	type Kind string
27	
28	const (
29		KindTestName   Kind = "test-name"
30		KindBuildGate  Kind = "build-gate"
31		KindNegative   Kind = "negative"
32		KindSymbol     Kind = "symbol"
33		KindMechanical Kind = "mechanical"
34		KindProse      Kind = "prose"
35	)
36	
37	// Result is the verdict on one AC item.
38	type Result string
39	
40	const (
41		ResultPass          Result = "pass"
42		ResultFail          Result = "fail"
43		ResultNeedsJudgment Result = "needs_judgment"
44		ResultError         Result = "error"
45	)
46	
47	// Item represents one parsed AC line with its classification.
48	type Item struct {
49		AC      int    // 1-based AC number
50		Text    string // original AC text (single line)
51		Kind    Kind   // classified kind
52		Name    string // extracted entity (test name, symbol, etc.); empty for prose
53		Alias   string // operator-declared substitution (e.g., TestFoo -> TestFoo/bar)
54	}
55	
56	// Output is the structured per-AC verification output written to
57	// .ddx/executions/<attempt-id>/ac-check.json.
58	type Output struct {
59		SchemaVersion int     `json:"schema_version"`
60		BeadID        string  `json:"bead_id"`
61		AttemptID     string  `json:"attempt_id,omitempty"`
62		Summary       Summary `json:"summary"`
63		Items         []Entry `json:"items"`
64	}
65	
66	// Summary aggregates counts across items.
67	type Summary struct {
68		Pass          int `json:"pass"`
69		Fail          int `json:"fail"`
70		NeedsJudgment int `json:"needs_judgment"`
71		Error         int `json:"error"`
72	}
73	
74	// Entry is one per-AC result in the structured output.
75	type Entry struct {
76		AC       int    `json:"ac"`
77		Kind     Kind   `json:"kind"`
78		Name     string `json:"name,omitempty"`
79		Result   Result `json:"result"`
80		Evidence string `json:"evidence"`
81	}
82	
83	// Context bundles the evaluator's inputs (working directory, diff range, package
84	// hint, optional ACAliases map). Tests inject this directly; the CLI builds it
85	// from flags.
86	type Context struct {
87		WorkingDir string
88		RevBase    string // typically "merge-base..HEAD" or a single ref; empty = no diff
89		Packages   []string
90		Aliases    map[int]string // AC number -> substitution (e.g. "TestFoo -> TestFoo/bar")
91	
92		// Test hooks. When non-nil, these replace the real implementations so tests
93		// can drive deterministic outcomes without invoking go/git subprocesses.
94		RunTest  func(name string, packages []string) (bool, string, error)
95		GitGrep  func(symbol string) (int, string, error) // returns hit count + sample
96		DiffHits func(symbol string) (int, error)         // hits in diff hunks specifically
97		FileInfo func(path string) (existsBefore, existsAfter bool, renamedFrom string)
98	}
99	
100	// ParseAcceptance splits the bead's acceptance text into numbered AC items.
101	// It recognises lines that start with "1.", "2.", etc., or "(a)", "(b)", etc.
102	// Continuation lines (no leading number) are appended to the prior item.
103	var itemHeadRE = regexp.MustCompile(`^\s*(?:(\d+)\.|\(([a-z])\))\s+(.*)$`)
104	
105	func ParseAcceptance(s string) []Item {
106		var items []Item
107		scanner := bufio.NewScanner(strings.NewReader(s))
108		scanner.Buffer(make([]byte, 64*1024), 1024*1024)
109		idx := 0
110		for scanner.Scan() {
111			line := scanner.Text()
112			if m := itemHeadRE.FindStringSubmatch(line); m != nil {
113				idx++
114				text := strings.TrimSpace(m[3])
115				items = append(items, Item{AC: idx, Text: text})
116			} else if len(items) > 0 {
117				trimmed := strings.TrimSpace(line)
118				if trimmed == "" {
119					continue
120				}
121				items[len(items)-1].Text += " " + trimmed
122			}
123		}
124		for i := range items {
125			items[i].Kind, items[i].Name = classify(items[i].Text)
126		}
127		return items
128	}
129	
130	// classify inspects an AC line and decides which mechanical evaluator should
131	// resolve it. Order matters: more-specific patterns first.
132	func classify(text string) (Kind, string) {
133		// 1. Backtick-symbol AC: `Foo.Bar()`, `pruneEvidenceDirs`, etc.
134		if m := backtickSymbolRE.FindStringSubmatch(text); m != nil {
135			// If the negative cue appears outside the backticks, this is a negative
136			// AC about the symbol, not a positive symbol AC.
137			if hasNegativeCue(text) {
138				return KindNegative, m[1]
139			}
140			return KindSymbol, m[1]
141		}
142	
143		// 2. Test-name AC: explicit Go test identifier.
144		if m := testNameRE.FindString(text); m != "" {
145			return KindTestName, m
146		}
147	
148		// 3. Build-gate AC: lefthook, go test ./..., pre-commit pass language.
149		if buildGateRE.MatchString(text) {
150			return KindBuildGate, ""
151		}
152	
153		// 4. Negative AC without backticks (still operates on a symbol name).
154		if hasNegativeCue(text) {
155			if name := extractNegativeSymbol(text); name != "" {
156				return KindNegative, name
157			}
158		}
159	
160		// 5. Mechanical AC: rename / doc / comment / file moves.
161		if mechanicalRE.MatchString(text) {
162			return KindMechanical, ""
163		}
164	
165		// 6. Default: prose.
166		return KindProse, ""
167	}
168	
169	var (
170		backtickSymbolRE = regexp.MustCompile("`([A-Za-z_][A-Za-z0-9_.]*(?:\\(\\))?)`")
171		testNameRE       = regexp.MustCompile(`\bTest[A-Z]\w*`)
172		buildGateRE      = regexp.MustCompile(`(?i)\b(lefthook|go test|go build|pre-commit|all pass|test.* green|tests? pass)\b`)
173		negativeCueRE    = regexp.MustCompile(`(?i)\b(no longer|does not|do not|never|removed?|cannot|must not|no calls? to|absence of|without|excluded from|stop tracking|untrack)\b`)
174		mechanicalRE     = regexp.MustCompile(`(?i)\b(rename|relocate(d|s)?|moved? to|file (exists?|present)|comment|docs?(\s+only)?|documentation|gitignore)\b`)
175		negSymbolWordRE  = regexp.MustCompile(`[A-Za-z_][A-Za-z0-9_.]{3,}`)
176	)
177	
178	func hasNegativeCue(s string) bool { return negativeCueRE.MatchString(s) }
179	
180	// extractNegativeSymbol pulls a plausible symbol token from a negative AC.
181	// Heuristic: longest identifier-like token after the negative cue.
182	func extractNegativeSymbol(text string) string {
183		loc := negativeCueRE.FindStringIndex(text)
184		if loc == nil {
185			return ""
186		}
187		tail := text[loc[1]:]
188		var best string
189		for _, m := range negSymbolWordRE.FindAllString(tail, -1) {
190			if len(m) > len(best) {
191				best = m
192			}
193		}
194		return best
195	}
196	
197	// Evaluate resolves each item to a result entry. ACAliases from ctx override
198	// the Name on a per-AC basis.
199	func Evaluate(items []Item, ctx Context) []Entry {
200		out := make([]Entry, 0, len(items))
201		for _, item := range items {
202			if alias, ok := ctx.Aliases[item.AC]; ok {
203				item.Alias = alias
204			}
205			out = append(out, evaluateOne(item, ctx))
206		}
207		return out
208	}
209	
210	func evaluateOne(item Item, ctx Context) Entry {
211		target := item.Name
212		if item.Alias != "" {
213			target = item.Alias
214		}
215		switch item.Kind {
216		case KindTestName:
217			return evalTestName(item, target, ctx)
218		case KindBuildGate:
219			return evalBuildGate(item, ctx)
220		case KindNegative:
221			return evalNegative(item, target, ctx)
222		case KindSymbol:
223			return evalSymbol(item, target, ctx)
224		case KindMechanical:
225			return evalMechanical(item, ctx)
226		default:
227			return Entry{
228				AC:       item.AC,
229				Kind:     KindProse,
230				Result:   ResultNeedsJudgment,
231				Evidence: "no mechanical anchor; defer to reviewer judgment",
232			}
233		}
234	}
235	
236	func evalTestName(item Item, target string, ctx Context) Entry {
237		e := Entry{AC: item.AC, Kind: KindTestName, Name: target}
238		if target == "" {
239			e.Result = ResultError
240			e.Evidence = "test-name AC could not resolve a test identifier"
241			return e
242		}
243		run := ctx.RunTest
244		if run == nil {
245			e.Result = ResultError
246			e.Evidence = "no test runner configured in context"
247			return e
248		}
249		ok, detail, err := run(target, ctx.Packages)
250		if err != nil {
251			e.Result = ResultError
252			e.Evidence = fmt.Sprintf("test runner error: %v", err)
253			return e
254		}
255		if ok {
256			e.Result = ResultPass
257			e.Evidence = fmt.Sprintf("test %s passed; %s", target, strings.TrimSpace(detail))
258			return e
259		}
260		e.Result = ResultFail
261		e.Evidence = fmt.Sprintf("test %s did not pass; %s", target, strings.TrimSpace(detail))
262		return e
263	}
264	
265	func evalBuildGate(item Item, ctx Context) Entry {
266		// Build gates are run separately (lefthook, go test ./...) by the orchestrator;
267		// here we report needs_judgment so the reviewer ratifies the orchestrator's
268		// exit code rather than the ac-check running them a second time.
269		return Entry{
270			AC:       item.AC,
271			Kind:     KindBuildGate,
272			Result:   ResultNeedsJudgment,
273			Evidence: "build/gate AC; orchestrator reports exit code separately",
274		}
275	}
276	
277	func evalNegative(item Item, target string, ctx Context) Entry {
278		e := Entry{AC: item.AC, Kind: KindNegative, Name: target}
279		if target == "" {
280			e.Result = ResultNeedsJudgment
281			e.Evidence = "negative AC without a resolvable symbol; defer to reviewer"
282			return e
283		}
284		grep := ctx.GitGrep
285		if grep == nil {
286			e.Result = ResultError
287			e.Evidence = "no git-grep hook configured in context"
288			return e
289		}
290		hits, sample, err := grep(target)
291		if err != nil {
292			e.Result = ResultError
293			e.Evidence = fmt.Sprintf("git-grep error: %v", err)
294			return e
295		}
296		if hits == 0 {
297			e.Result = ResultPass
298			e.Evidence = fmt.Sprintf("symbol %q has 0 hits in post-image; absence confirmed", target)
299			return e
300		}
301		e.Result = ResultFail
302		e.Evidence = fmt.Sprintf("symbol %q still has %d hits in post-image; AC requires absence (%s)", target, hits, strings.TrimSpace(sample))
303		return e
304	}
305	
306	func evalSymbol(item Item, target string, ctx Context) Entry {
307		e := Entry{AC: item.AC, Kind: KindSymbol, Name: target}
308		if target == "" {
309			e.Result = ResultError
310			e.Evidence = "symbol AC could not resolve an identifier"
311			return e
312		}
313		grep := ctx.GitGrep
314		if grep == nil {
315			e.Result = ResultError
316			e.Evidence = "no git-grep hook configured in context"
317			return e
318		}
319		hits, sample, err := grep(target)
320		if err != nil {
321			e.Result = ResultError
322			e.Evidence = fmt.Sprintf("git-grep error: %v", err)
323			return e
324		}
325		if hits == 0 {
326			e.Result = ResultFail
327			e.Evidence = fmt.Sprintf("symbol %q has 0 hits in post-image; AC requires its presence", target)
328			return e
329		}
330		diffHits := 0
331		if ctx.DiffHits != nil {
332			dh, derr := ctx.DiffHits(target)
333			if derr == nil {
334				diffHits = dh
335			}
336		}
337		if diffHits == 0 {
338			e.Result = ResultFail
339			e.Evidence = fmt.Sprintf("symbol %q exists (%d hits) but does NOT appear in diff; AC asks for an added/touched change", target, hits)
340			return e
341		}
342		e.Result = ResultPass
343		e.Evidence = fmt.Sprintf("symbol %q present with %d hits; diff touches %d (%s)", target, hits, diffHits, strings.TrimSpace(sample))
344		return e
345	}
346	
347	func evalMechanical(item Item, ctx Context) Entry {
348		// Mechanical ACs are file-presence / rename detection. Without a specific
349		// path, we yield needs_judgment so the reviewer adjudicates after seeing the
350		// diff name-status.
351		return Entry{
352			AC:       item.AC,
353			Kind:     KindMechanical,
354			Result:   ResultNeedsJudgment,
355			Evidence: "mechanical AC; reviewer adjudicates against diff name-status",
356		}
357	}
