404	// DefaultGitGrep returns a GitGrep hook that runs `git grep -c <symbol>`
405	// inside workingDir. Empty string symbols are rejected.
406	func DefaultGitGrep(workingDir string) func(symbol string) (int, string, error) {
407		return func(symbol string) (int, string, error) {
408			if symbol == "" {
409				return 0, "", fmt.Errorf("empty symbol")
410			}
411			// Use a fixed-string match to avoid regex surprises.
412			cmd := exec.Command("git", "grep", "-c", "-F", "--", symbol)
413			cmd.Dir = workingDir
414			out, _ := cmd.Output() // exit=1 means no match; not an error here
415			hits := 0
416			sample := ""
417			for _, line := range strings.Split(strings.TrimSpace(string(out)), "\n") {
418				if line == "" {
419					continue
420				}
421				// format: "path/file.go:N"
422				parts := strings.SplitN(line, ":", 2)
423				if len(parts) == 2 {
424					// best-effort numeric
425					var n int
426					if _, err := fmt.Sscanf(parts[1], "%d", &n); err == nil {
427						hits += n
428					}
429				}
430				if sample == "" {
431					sample = line
432				}
433			}
434			return hits, sample, nil
435		}
436	}
437	
438	// DefaultDiffHits returns a DiffHits hook that counts occurrences of symbol in
439	// `git diff <base>..HEAD` output. base may be empty (no diff filter).
440	func DefaultDiffHits(workingDir, base string) func(symbol string) (int, error) {
441		return func(symbol string) (int, error) {
442			if symbol == "" {
443				return 0, nil
444			}
445			args := []string{"diff"}
446			if base != "" {
447				args = append(args, base)
448			}
449			cmd := exec.Command("git", args...)
450			cmd.Dir = workingDir
451			out, err := cmd.Output()
452			if err != nil {
453				return 0, err
454			}
455			return strings.Count(string(out), symbol), nil
456		}
457	}
458	
459	// DefaultRunTest returns a RunTest hook that invokes `go test -run '^<name>$'`
460	// against the given packages (or `./...` if none).
461	func DefaultRunTest(workingDir string) func(name string, packages []string) (bool, string, error) {
462		return func(name string, packages []string) (bool, string, error) {
463			args := []string{"test", "-run", "^" + regexp.QuoteMeta(name) + "$", "-count=1", "-short"}
464			if len(packages) == 0 {
465				args = append(args, "./...")
466			} else {
467				args = append(args, packages...)
468			}
469			cmd := exec.Command("go", args...)
470			cmd.Dir = filepath.Join(workingDir, "cli") // tests live under cli/
471			out, err := cmd.CombinedOutput()
472			text := strings.TrimSpace(string(out))
473			if err != nil {
474				return false, text, nil // test failure surfaces as ok=false, err nil
475			}
476			// `go test` exits 0 also when no tests match; detect that case.
477			if strings.Contains(text, "[no tests to run]") || strings.Contains(text, "no test files") {
478				return false, text + " (no matching test found)", nil
479			}
480			return true, text, nil
481		}
482	}
