23	// ReviewVerdict is the parsed JSON contract emitted by the reviewer agent.
24	// It replaces the markdown extractor that silently mis-parsed `### Verdict:
25	// APPROVE` outputs whenever the model echoed the prompt's options-header
26	// line (the upstream-report regression). The parser is strict: unknown
27	// verdict values, missing verdict field, and truncated/unfenced JSON all
28	// surface as ErrReviewVerdictUnparseable.
29	type ReviewVerdict struct {
30		SchemaVersion int        `json:"schema_version,omitempty"`
31		Verdict       Verdict    `json:"verdict"`
