829	func mergeLatestCandidateCycleRunState(projectRoot string, state RunState) RunState {
830		states, err := ReadRunStates(projectRoot)
831		if err != nil {
832			return state
833		}
834		for i := range states {
835			current := states[i]
836			if state.AttemptID != "" && current.AttemptID != state.AttemptID {
837				continue
838			}
839			if state.AttemptID == "" && state.WorktreePath != "" && current.WorktreePath != "" &&
840				filepath.Clean(current.WorktreePath) != filepath.Clean(state.WorktreePath) {
841				continue
842			}
843			state.CandidateCyclePhase = current.CandidateCyclePhase
844			state.CandidateRef = current.CandidateRef
845			state.CandidateRev = current.CandidateRev
846			state.CycleIndex = current.CycleIndex
847			state.ReviewActive = current.ReviewActive
848			state.RepairActive = current.RepairActive
849			return state
850		}
851		return state
852	}
