49	//     verdict.
50	//
51	// It rejects:
52	//   - empty input;
53	//   - inputs containing no JSON object at all;
54	//   - JSON missing the "verdict" field;
55	//   - unknown verdict values (anything other than APPROVE,
56	//     REQUEST_CHANGES, BLOCK);
57	//   - truncated/malformed JSON.
58	//
59	// Unknown fields outside the schema are tolerated (forward-compat).
60	func ParseReviewVerdict(raw []byte) (ReviewVerdict, error) {
61		if len(strings.TrimSpace(string(raw))) == 0 {
62			return ReviewVerdict{}, fmt.Errorf("%w: empty input", ErrReviewVerdictUnparseable)
63		}
64		candidate, ok := extractJSONCandidate(string(raw))
65		if !ok {
66			return ReviewVerdict{}, fmt.Errorf("%w: no JSON object found", ErrReviewVerdictUnparseable)
67		}
68	
69		// First decode into a generic shape so we can validate the verdict
70		// field's presence and value before binding to ReviewVerdict.
71		var probe map[string]json.RawMessage
72		if err := json.Unmarshal([]byte(candidate), &probe); err != nil {
73			return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
74		}
75		rawVerdict, ok := probe["verdict"]
76		if !ok {
77			return ReviewVerdict{}, fmt.Errorf("%w: missing verdict field", ErrReviewVerdictUnparseable)
78		}
79		var verdictStr string
80		if err := json.Unmarshal(rawVerdict, &verdictStr); err != nil {
81			return ReviewVerdict{}, fmt.Errorf("%w: verdict not a string: %v", ErrReviewVerdictUnparseable, err)
82		}
83		switch Verdict(verdictStr) {
84		case VerdictApprove, VerdictRequestChanges, VerdictBlock:
85		default:
86			return ReviewVerdict{}, fmt.Errorf("%w: unknown verdict %q", ErrReviewVerdictUnparseable, verdictStr)
87		}
88	
89		var rv ReviewVerdict
90		if err := json.Unmarshal([]byte(candidate), &rv); err != nil {
91			return ReviewVerdict{}, fmt.Errorf("%w: %v", ErrReviewVerdictUnparseable, err)
92		}
93		return rv, nil
94	}
95	
96	// extractJSONCandidate returns the JSON object payload from a raw reviewer
97	// output. Resolution order:
98	//  1. The last ```json … ``` fenced block (handles models that wrap output).
99	//  2. The last ``` … ``` fenced block when its body parses as a JSON object.
100	//  3. The substring from the first '{' that balances braces (handles raw
101	//     JSON or JSON with leading prose).
102	//
103	// Returns ok=false when no plausible JSON object is found.
104	func extractJSONCandidate(s string) (string, bool) {
105		if c, ok := lastFencedBlock(s, "json"); ok {
106			return strings.TrimSpace(c), true
107		}
108		if c, ok := lastFencedBlock(s, ""); ok {
109			trimmed := strings.TrimSpace(c)
110			if strings.HasPrefix(trimmed, "{") {
111				return trimmed, true
112			}
113		}
114		if c, ok := firstBalancedObject(s); ok {
115			return c, true
116		}
117		return "", false
118	}
119	
120	// lastFencedBlock returns the body of the LAST ```<lang> … ``` fenced block
121	// in s. lang="" matches any fence ("``` … ```"). Returns ok=false when no
122	// matching fence is found or the fence is unterminated.
123	func lastFencedBlock(s, lang string) (string, bool) {
124		open := "```"
125		if lang != "" {
126			open = "```" + lang
127		}
128		var found string
129		var ok bool
130		idx := 0
131		for {
132			i := indexFromAny(s, idx, open)
133			if i < 0 {
134				break
135			}
136			// Ensure the fence is followed by newline or whitespace (avoid
137			// matching ```jsonc when looking for ```json).
138			afterOpen := i + len(open)
139			if afterOpen < len(s) {
140				c := s[afterOpen]
141				if lang != "" && c != '\n' && c != '\r' && c != ' ' && c != '\t' {
142					idx = i + len(open)
143					continue
144				}
145			}
146			bodyStart := afterOpen
147			// Skip a single trailing newline after the opening fence.
148			if bodyStart < len(s) && s[bodyStart] == '\n' {
149				bodyStart++
150			} else if bodyStart+1 < len(s) && s[bodyStart] == '\r' && s[bodyStart+1] == '\n' {
151				bodyStart += 2
152			}
153			// Find closing fence.
154			j := strings.Index(s[bodyStart:], "```")
155			if j < 0 {
156				break
157			}
158			body := s[bodyStart : bodyStart+j]
159			// Strip a single trailing newline before the closing fence.
160			body = strings.TrimRight(body, "\n\r")
161			found = body
162			ok = true
163			idx = bodyStart + j + 3
164		}
165		return found, ok
166	}
167	
168	// indexFromAny is strings.Index but starting at the given offset.
169	func indexFromAny(s string, from int, sub string) int {
170		if from >= len(s) {
171			return -1
172		}
173		i := strings.Index(s[from:], sub)
174		if i < 0 {
175			return -1
176		}
177		return from + i
178	}
179	
180	// firstBalancedObject scans for the first '{' in s and returns the substring
181	// that closes its outermost JSON object, respecting strings and escapes.
182	// Returns ok=false on no opening brace or on an unterminated object.
183	func firstBalancedObject(s string) (string, bool) {
184		start := strings.Index(s, "{")
185		if start < 0 {
186			return "", false
187		}
188		depth := 0
189		inString := false
190		escape := false
191		for i := start; i < len(s); i++ {
192			c := s[i]
193			if escape {
194				escape = false
195				continue
196			}
197			if inString {
198				switch c {
199				case '\\':
200					escape = true
201				case '"':
202					inString = false
203				}
204				continue
205			}
206			switch c {
207			case '"':
208				inString = true
209			case '{':
210				depth++
211			case '}':
212				depth--
213				if depth == 0 {
214					return s[start : i+1], true
215				}
216			}
217		}
218		return "", false
219	}
