3200	// ClassifyReviewError maps a reviewer error and partial result into one of the
3201	// four FEAT-022 §12 taxonomy classes. Resolution order:
3202	//  1. reviewRes.Error if it's already one of the canonical class identifiers
3203	//     (the reviewer set it explicitly — preferred path).
3204	//  2. The error string text (for backwards-compatible reviewers that only
3205	//     embed the class in their message).
3206	//  3. ErrReviewVerdictUnparseable as a fallback when the strict-parse error
3207	//     leaks through a reviewer that did not set Error.
3208	//  4. Default to transport (network/provider-side failure) when nothing else
3209	//     matches.
3210	func ClassifyReviewError(reviewErr error, reviewRes *ReviewResult) string {
3211		if reviewRes != nil {
3212			switch reviewRes.Error {
3213			case evidence.OutcomeReviewContextOverflow,
3214				evidence.OutcomeReviewProviderEmpty,
3215				evidence.OutcomeReviewUnparseable,
3216				evidence.OutcomeReviewTransport,
3217				evidence.OutcomeReviewCostCapExceeded,
3218				evidence.OutcomeReviewReviewerUnavailable:
3219				return reviewRes.Error
3220			}
3221		}
3222		msg := ""
3223		if reviewErr != nil {
3224			msg = reviewErr.Error()
3225		}
3226		switch {
3227		case strings.Contains(msg, evidence.OutcomeReviewContextOverflow):
3228			return evidence.OutcomeReviewContextOverflow
3229		case strings.Contains(msg, evidence.OutcomeReviewCostCapExceeded):
3230			return evidence.OutcomeReviewCostCapExceeded
3231		case strings.Contains(msg, evidence.OutcomeReviewReviewerUnavailable):
3232			return evidence.OutcomeReviewReviewerUnavailable
3233		case strings.Contains(msg, evidence.OutcomeReviewProviderEmpty):
3234			return evidence.OutcomeReviewProviderEmpty
3235		case strings.Contains(msg, evidence.OutcomeReviewUnparseable):
3236			return evidence.OutcomeReviewUnparseable
3237		case strings.Contains(msg, evidence.OutcomeReviewTransport):
3238			return evidence.OutcomeReviewTransport
3239		case reviewErr != nil && strings.Contains(msg, ErrReviewVerdictUnparseable.Error()):
3240			return evidence.OutcomeReviewUnparseable
3241		}
3242		return evidence.OutcomeReviewTransport
3243	}
