10	// ReviewFindingClassification is the strict retry/manual class derived from
11	// structured review evidence. Rationale is retained for operator context, but
12	// freeform rationale alone is not evidence and cannot make a result repairable.
13	type ReviewFindingClassification struct {
14		Class                   string
15		Evidence                []string
16		AutomatedRepairEligible bool
17		Reason                  string
18	}
19	
20	// ClassifyReviewFindings maps a structured reviewer result to the FEAT-010
21	// review classes used as the policy boundary before repair or manual routing.
22	func ClassifyReviewFindings(res *ReviewResult) ReviewFindingClassification {
23		if res == nil {
24			return reviewClassification(ReviewFindingClassMalfunction, nil, "missing review result", false)
25		}
26	
27		switch res.Verdict {
28		case VerdictApprove:
29			return ReviewFindingClassification{}
30		case VerdictRequestChanges, VerdictBlock:
31		default:
32			return reviewClassification(ReviewFindingClassMalfunction, nil, "malformed review verdict", false)
33		}
34	
35		evidence := reviewStructuredEvidence(res)
36		if len(evidence) == 0 {
37			return reviewClassification(ReviewFindingClassMalfunction, nil, "review lacks structured findings or per-AC evidence", false)
38		}
39	
40		text := strings.ToLower(strings.Join(evidence, "\n"))
41		switch {
42		case containsAny(text, ReviewTerminalClassUnsafeOrOutScope, "unsafe", "out of scope", "out-of-scope", "outside scope", "non-scope", "forbidden", "scope change", "destructive"):
43			return reviewClassification(ReviewTerminalClassUnsafeOrOutScope, evidence, "", false)
44		case containsAny(text, ReviewTerminalClassTooLarge, "too large", "too broad", "decompose", "split this bead", "split the bead", "needs decomposition"):
45			return reviewClassification(ReviewTerminalClassTooLarge, evidence, "", false)
46		case containsAny(text, ReviewTerminalClassSpecGap, "spec gap", "specification gap", "contradictory", "contradiction", "ambiguous requirement", "requirements are unclear", "unclear requirement"):
47			return reviewClassification(ReviewTerminalClassSpecGap, evidence, "", false)
48		case containsAny(text, ReviewTerminalClassMissingAcceptance, "missing acceptance", "acceptance criteria missing", "acceptance criterion missing", "unverifiable acceptance", "acceptance is unverifiable"):
49			return reviewClassification(ReviewTerminalClassMissingAcceptance, evidence, "", false)
50		default:
51			return reviewClassification(ReviewFindingClassFixableGap, evidence, "", true)
52		}
53	}
54	
55	func reviewClassification(class string, evidence []string, reason string, repair bool) ReviewFindingClassification {
56		return ReviewFindingClassification{
57			Class:                   class,
58			Evidence:                append([]string(nil), evidence...),
59			AutomatedRepairEligible: repair,
60			Reason:                  strings.TrimSpace(reason),
61		}
62	}
63	
64	func reviewStructuredEvidence(res *ReviewResult) []string {
65		if res == nil {
66			return nil
67		}
68		var evidence []string
69		for _, ac := range res.PerAC {
70			if strings.TrimSpace(ac.Evidence) == "" {
71				continue
72			}
73			parts := []string{ac.Item, ac.Grade, ac.Evidence}
74			line := strings.TrimSpace(strings.Join(parts, " "))
75			if line != "" {
76				evidence = append(evidence, line)
77			}
78		}
79		for _, finding := range res.Findings {
80			summary := strings.TrimSpace(finding.Summary)
81			if summary == "" {
82				continue
83			}
84			if loc := strings.TrimSpace(finding.Location); loc != "" {
85				summary = loc + ": " + summary
86			}
87			if sev := strings.TrimSpace(finding.Severity); sev != "" {
88				summary = sev + ": " + summary
89			}
90			evidence = append(evidence, summary)
91		}
92		return evidence
93	}
