688	// appendBeadRoutingEvidence records a kind:routing evidence entry on the bead
689	// after an agent run. It is a best-effort operation — errors are silently
690	// ignored so a store failure never aborts the main execute-bead flow.
691	//
692	// The body separates requested passthrough constraints (harness/provider/model
693	// from the CLI envelope) and requested power bounds from the actual resolved
694	// values so analytics can distinguish intent from outcome (AC5 of ddx-20047dd5).
695	func appendBeadRoutingEvidence(appender BeadEventAppender, beadID, harness, provider, model, routeReason, baseURL string, passthrough config.AgentPassthrough, minPower, maxPower, actualPower int) {
696		if appender == nil || beadID == "" {
697			return
698		}
699		resolvedProvider := provider
700		if resolvedProvider == "" {
701			resolvedProvider = harness
702		}
703		type routingBody struct {
704			ResolvedProvider  string   `json:"resolved_provider"`
705			ResolvedModel     string   `json:"resolved_model,omitempty"`
706			RouteReason       string   `json:"route_reason,omitempty"`
707			FallbackChain     []string `json:"fallback_chain"`
708			BaseURL           string   `json:"base_url,omitempty"`
709			RequestedHarness  string   `json:"requested_harness,omitempty"`
710			RequestedProvider string   `json:"requested_provider,omitempty"`
711			RequestedModel    string   `json:"requested_model,omitempty"`
712			RequestedMinPower int      `json:"requested_min_power,omitempty"`
713			RequestedMaxPower int      `json:"requested_max_power,omitempty"`
714			ActualPower       int      `json:"actual_power,omitempty"`
715		}
716		body := routingBody{
717			ResolvedProvider:  resolvedProvider,
718			ResolvedModel:     model,
719			RouteReason:       routeReason,
720			FallbackChain:     []string{},
721			BaseURL:           baseURL,
722			RequestedHarness:  passthrough.Harness,
723			RequestedProvider: passthrough.Provider,
724			RequestedModel:    passthrough.Model,
725			RequestedMinPower: minPower,
726			RequestedMaxPower: maxPower,
727			ActualPower:       actualPower,
728		}
729		data, err := json.Marshal(body)
730		if err != nil {
731			return
732		}
733		summary := fmt.Sprintf("provider=%s", resolvedProvider)
734		if model != "" {
735			summary += fmt.Sprintf(" model=%s", model)
736		}
737		if routeReason != "" {
738			summary += fmt.Sprintf(" reason=%s", routeReason)
739		}
740		_ = appender.AppendEvent(beadID, bead.BeadEvent{
741			Kind:    "routing",
742			Summary: summary,
743			Body:    string(data),
744			Actor:   "ddx",
745			Source:  "ddx agent execute-bead",
746		})
747	}
