765	// appendBeadCostEvidence records a kind:cost evidence entry on the bead with
766	// per-attempt token and dollar usage. Best-effort: errors are discarded so a
767	// store failure never aborts the main execute-bead flow. Emits nothing when
768	// the appender is nil, the beadID is empty, or every cost field is zero
769	// (e.g., dry-run, no-changes with no provider call).
770	func appendBeadCostEvidence(appender BeadEventAppender, beadID, attemptID string, body costEventBody) {
771		if appender == nil || beadID == "" {
772			return
773		}
774		if body.InputTokens == 0 && body.OutputTokens == 0 && body.TotalTokens == 0 && body.CostUSD == 0 {
775			return
776		}
777		body.AttemptID = attemptID
778		if body.TotalTokens == 0 {
779			body.TotalTokens = body.InputTokens + body.OutputTokens
780		}
781		data, err := json.Marshal(body)
782		if err != nil {
783			return
784		}
785		var summary string
786		if body.CostUSD > 0 {
787			summary = fmt.Sprintf("tokens=%d cost_usd=%.4f", body.TotalTokens, body.CostUSD)
788		} else {
789			summary = fmt.Sprintf("tokens=%d", body.TotalTokens)
790		}
791		if body.Model != "" {
792			summary += fmt.Sprintf(" model=%s", body.Model)
793		}
794		_ = appender.AppendEvent(beadID, bead.BeadEvent{
795			Kind:    "cost",
796			Summary: summary,
797			Body:    string(data),
798			Actor:   "ddx",
799			Source:  "ddx agent execute-bead",
800		})
801	}
