803	func startRunStateRefresh(ctx context.Context, projectRoot string, state RunState) func() {
804		interval := RunStateRefreshInterval
805		if interval <= 0 {
806			interval = 10 * time.Second
807		}
808		ctx, cancel := context.WithCancel(ctx)
809		done := make(chan struct{})
810		go func() {
811			defer close(done)
812			ticker := time.NewTicker(interval)
813			defer ticker.Stop()
814			for {
815				select {
816				case <-ctx.Done():
817					return
818				case <-ticker.C:
819					_ = WriteRunState(projectRoot, mergeLatestCandidateCycleRunState(projectRoot, state))
820				}
821			}
822		}()
823		return func() {
824			cancel()
825			<-done
826		}
827	}
