854	func buildAttemptDiagnostic(projectRoot, wtPath, beadID, attemptID, headRevErr string, gitOps GitOps) *AttemptDiagnostic {
855		diag := &AttemptDiagnostic{
856			BeadID:       beadID,
857			AttemptID:    attemptID,
858			WorktreePath: wtPath,
859			HeadRevError: headRevErr,
860		}
861		if _, err := os.Stat(wtPath); err == nil {
862			diag.WorktreePathExists = true
863		}
864		if _, err := ReadExecutionCleanupMetadata(wtPath); err == nil {
865			diag.CleanupMetadataPresent = true
866		}
867		if states, err := ReadRunStates(projectRoot); err == nil {
868			if state := matchingRunStateForAttempt(states, attemptID, wtPath); state != nil {
869				diag.RunStatePresent = true
870				copied := *state
871				diag.RunState = &copied
872			}
873		}
874		if gitOps != nil {
875			if paths, err := gitOps.WorktreeList(projectRoot); err == nil {
876				for _, path := range paths {
877					if filepath.Clean(path) == filepath.Clean(wtPath) {
878						diag.GitWorktreeRegistered = true
879						break
880					}
881				}
882			}
883		}
884		return diag
885	}
