887	func matchingRunStateForAttempt(states []RunState, attemptID, wtPath string) *RunState {
888		for i := range states {
889			if attemptID != "" && states[i].AttemptID == attemptID {
890				return &states[i]
891			}
892			if wtPath != "" && states[i].WorktreePath != "" && filepath.Clean(states[i].WorktreePath) == filepath.Clean(wtPath) {
893				return &states[i]
894			}
895		}
896		return nil
897	}
